import React, { useEffect, useMemo, useState } from 'react'
import { useDispatch, useSelector } from 'react-redux'
import toast from 'react-hot-toast'
import { fetchMyOrders, selectOrders } from '../../redux/orderSlice'
import { selectCurrentUser } from '../../redux/authSlice'
import { authApi } from '../../api/authApi'
import { formatDate, formatDateTime, formatPrice } from '../../utils/helpers'
import Loader from '../../components/common/Loader'
import notify from '../../utils/notification'

export default function Profile() {
  const dispatch = useDispatch()
  const user = useSelector(selectCurrentUser)
  const orders = useSelector(selectOrders)
  const [name, setName] = useState(user?.name || '')
  const [currentPassword, setCurrentPassword] = useState('')
  const [newPassword, setNewPassword] = useState('')
  const [addresses, setAddresses] = useState(user?.addresses || [])
  const [newAddress, setNewAddress] = useState({ street: '', city: '', pincode: '' })
  const [saving, setSaving] = useState(false)
  const [passwordSaving, setPasswordSaving] = useState(false)
  const [activeTab, setActiveTab] = useState('profile')

  useEffect(() => {
    if (user) {
      setName(user.name || '')
      setAddresses(user.addresses || [])
    }
  }, [user])

  useEffect(() => {
    dispatch(fetchMyOrders())
  }, [dispatch])

  const stats = useMemo(() => ({
    totalOrders: orders.length,
    totalSpent: orders.reduce((total, order) => total + (order.totalPrice || 0), 0),
    lastOrder: orders[0],
  }), [orders])

  const handleProfileSave = async () => {
    try {
      setSaving(true)
      const { data } = await authApi.updateProfile({ name })
      notify.profileUpdated()
    } catch (err) {
      const msg = err.response?.data?.message || 'Unable to update profile'
      notify.error(msg)
    } finally {
      setSaving(false)
    }
  }

  const handleChangePassword = async () => {
    if (!currentPassword || !newPassword) {
      notify.error('Please fill in both password fields')
      return
    }

    try {
      setPasswordSaving(true)
      await authApi.changePassword(currentPassword, newPassword)
      setCurrentPassword('')
      setNewPassword('')
      notify.passwordChanged()
    } catch (err) {
      const msg = err.response?.data?.message || 'Unable to update password'
      notify.error(msg)
    } finally {
      setPasswordSaving(false)
    }
  }

  const handleAddAddress = () => {
    if (!newAddress.street || !newAddress.city || !newAddress.pincode) {
      notify.error('Please fill in all address fields')
      return
    }
    setAddresses([...addresses, { ...newAddress, id: Date.now() }])
    setNewAddress({ street: '', city: '', pincode: '' })
    notify.success('Address added successfully')
  }

  const handleRemoveAddress = (id) => {
    setAddresses(addresses.filter((addr) => addr.id !== id))
    notify.success('Address removed')
  }

  if (!user) return <Loader fullScreen />

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <div className="mb-8 space-y-3">
        <p className="text-sm uppercase tracking-[0.22em] text-primary-600">Account</p>
        <h1 className="text-3xl font-semibold text-slate-900">Your profile</h1>
        <p className="max-w-2xl text-slate-600">Manage your account, orders, addresses, and security settings.</p>
      </div>

      {/* Tab Navigation */}
      <div className="mb-8 flex gap-2 border-b border-slate-200">
        {[
          { id: 'profile', label: 'Profile' },
          { id: 'addresses', label: 'Addresses' },
          { id: 'security', label: 'Security' },
          { id: 'orders', label: 'Orders' },
        ].map((tab) => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`px-4 py-3 text-sm font-semibold border-b-2 transition ${
              activeTab === tab.id
                ? 'border-primary-600 text-primary-600'
                : 'border-transparent text-slate-600 hover:text-slate-900'
            }`}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {/* Profile Tab */}
      {activeTab === 'profile' && (
        <section className="space-y-6 rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
          <div className="space-y-2">
            <h2 className="text-xl font-semibold text-slate-900">Profile details</h2>
            <p className="text-sm text-slate-500">Your main account settings are stored securely.</p>
          </div>

          <div className="grid gap-4 sm:grid-cols-2">
            <label className="space-y-2">
              <span className="text-sm font-medium text-slate-700">Name</span>
              <input
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full rounded-3xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm outline-none focus:border-primary-500"
              />
            </label>
            <label className="space-y-2">
              <span className="text-sm font-medium text-slate-700">Email</span>
              <input
                value={user.email}
                readOnly
                className="w-full rounded-3xl border border-slate-200 bg-slate-100 px-4 py-3 text-sm text-slate-500"
              />
            </label>
          </div>

          <div className="grid gap-4 sm:grid-cols-2">
            <div className="rounded-3xl bg-slate-50 p-4">
              <p className="text-xs uppercase tracking-[0.24em] text-slate-500">Joined</p>
              <p className="mt-2 font-semibold text-slate-900">{formatDate(user.createdAt)}</p>
            </div>
            <div className="rounded-3xl bg-slate-50 p-4">
              <p className="text-xs uppercase tracking-[0.24em] text-slate-500">Recent order</p>
              <p className="mt-2 font-semibold text-slate-900">{stats.lastOrder ? formatDateTime(stats.lastOrder.createdAt) : 'No orders yet'}</p>
            </div>
          </div>

          <button
            type="button"
            onClick={handleProfileSave}
            disabled={saving}
            className="rounded-full bg-primary-600 px-6 py-3 text-sm font-semibold text-white transition hover:bg-primary-700 disabled:cursor-not-allowed disabled:opacity-60"
          >
            Save profile
          </button>
        </section>
      )}

      {/* Addresses Tab */}
      {activeTab === 'addresses' && (
        <section className="space-y-6 rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
          <div className="space-y-2">
            <h2 className="text-xl font-semibold text-slate-900">Delivery addresses</h2>
            <p className="text-sm text-slate-500">Manage your saved delivery addresses.</p>
          </div>

          <div className="space-y-4">
            {addresses.length > 0 && (
              <div className="space-y-3">
                <p className="text-sm font-medium text-slate-700">Saved addresses</p>
                {addresses.map((addr) => (
                  <div key={addr.id} className="flex items-start justify-between rounded-3xl border border-slate-200 bg-slate-50 p-4">
                    <div>
                      <p className="font-medium text-slate-900">{addr.street}</p>
                      <p className="text-sm text-slate-600">{addr.city}, {addr.pincode}</p>
                    </div>
                    <button
                      onClick={() => handleRemoveAddress(addr.id)}
                      className="rounded-full bg-rose-100 px-3 py-1 text-xs font-semibold text-rose-700 hover:bg-rose-200"
                    >
                      Remove
                    </button>
                  </div>
                ))}
              </div>
            )}

            <div className="rounded-3xl border-2 border-dashed border-slate-300 p-4">
              <p className="mb-3 text-sm font-medium text-slate-700">Add new address</p>
              <div className="space-y-3">
                <input
                  value={newAddress.street}
                  onChange={(e) => setNewAddress({ ...newAddress, street: e.target.value })}
                  placeholder="Street address"
                  className="w-full rounded-3xl border border-slate-200 bg-white px-4 py-3 text-sm outline-none focus:border-primary-500"
                />
                <div className="grid gap-3 sm:grid-cols-2">
                  <input
                    value={newAddress.city}
                    onChange={(e) => setNewAddress({ ...newAddress, city: e.target.value })}
                    placeholder="City"
                    className="w-full rounded-3xl border border-slate-200 bg-white px-4 py-3 text-sm outline-none focus:border-primary-500"
                  />
                  <input
                    value={newAddress.pincode}
                    onChange={(e) => setNewAddress({ ...newAddress, pincode: e.target.value })}
                    placeholder="Pincode"
                    className="w-full rounded-3xl border border-slate-200 bg-white px-4 py-3 text-sm outline-none focus:border-primary-500"
                  />
                </div>
                <button
                  onClick={handleAddAddress}
                  className="w-full rounded-full bg-primary-600 px-4 py-3 text-sm font-semibold text-white transition hover:bg-primary-700"
                >
                  Add address
                </button>
              </div>
            </div>
          </div>
        </section>
      )}

      {/* Security Tab */}
      {activeTab === 'security' && (
        <section className="space-y-6 rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
          <div className="space-y-2">
            <h2 className="text-xl font-semibold text-slate-900">Security</h2>
            <p className="text-sm text-slate-500">Update your password on a secure connection.</p>
          </div>

          <label className="space-y-2">
            <span className="text-sm font-medium text-slate-700">Current password</span>
            <input
              type="password"
              value={currentPassword}
              onChange={(e) => setCurrentPassword(e.target.value)}
              className="w-full rounded-3xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm outline-none focus:border-primary-500"
            />
          </label>

          <label className="space-y-2">
            <span className="text-sm font-medium text-slate-700">New password</span>
            <input
              type="password"
              value={newPassword}
              onChange={(e) => setNewPassword(e.target.value)}
              className="w-full rounded-3xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm outline-none focus:border-primary-500"
            />
          </label>

          <button
            type="button"
            onClick={handleChangePassword}
            disabled={passwordSaving}
            className="rounded-full bg-slate-900 px-6 py-3 text-sm font-semibold text-white transition hover:bg-slate-800 disabled:cursor-not-allowed disabled:opacity-60"
          >
            Change password
          </button>
        </section>
      )}

      {/* Orders Tab */}
      {activeTab === 'orders' && (
        <section className="space-y-6 rounded-[2rem] border border-slate-200 bg-white p-6 shadow-sm">
          <div className="space-y-2">
            <h2 className="text-xl font-semibold text-slate-900">Order history</h2>
            <p className="text-sm text-slate-500">Track all your orders and purchases.</p>
          </div>

          <div className="grid gap-4 sm:grid-cols-2">
            <div className="rounded-3xl bg-slate-50 p-4">
              <p className="text-xs uppercase tracking-[0.24em] text-slate-500">Total orders</p>
              <p className="mt-2 text-3xl font-semibold text-slate-900">{stats.totalOrders}</p>
            </div>
            <div className="rounded-3xl bg-slate-50 p-4">
              <p className="text-xs uppercase tracking-[0.24em] text-slate-500">Total spent</p>
              <p className="mt-2 text-3xl font-semibold text-slate-900">{formatPrice(stats.totalSpent)}</p>
            </div>
          </div>

          <div className="space-y-3">
            {orders.length ? (
              orders.map((order) => (
                <div key={order._id} className="rounded-3xl border border-slate-200 bg-slate-50 p-4">
                  <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                    <div>
                      <p className="font-semibold text-slate-900">#{order._id?.slice(-8).toUpperCase()}</p>
                      <p className="text-xs text-slate-500">{formatDateTime(order.createdAt)}</p>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-sm text-slate-600">{order.pizzas?.length ? `${order.pizzas.length} item(s)` : 'Custom pizza'}</span>
                      <span className="rounded-full bg-primary-100 px-3 py-1 text-sm font-semibold text-primary-700">{formatPrice(order.totalPrice)}</span>
                    </div>
                  </div>
                  <div className="mt-3 flex items-center gap-2">
                    <span className={`rounded-full px-3 py-1 text-xs font-semibold ${
                      order.status === 'Delivered'
                        ? 'bg-emerald-100 text-emerald-700'
                        : 'bg-amber-100 text-amber-700'
                    }`}>
                      {order.status || 'Processing'}
                    </span>
                  </div>
                </div>
              ))
            ) : (
              <div className="rounded-3xl border border-dashed border-slate-300 bg-slate-50 p-8 text-center text-slate-500">
                No orders yet. Start browsing the menu to place your first order.
              </div>
            )}
          </div>
        </section>
      )}
    </div>
  )
}
